private setupFileSystemWatcher(): void {
	// Create watchers for all workspace folders to detect file system changes
	const createWatcher = (workspaceFolder: vscode.WorkspaceFolder) => {
		const pattern = new vscode.RelativePattern(workspaceFolder.uri, '**/*.{ts,tsx,js,jsx,mts,cts,mjs,cjs}');
		const watcher = this._register(vscode.workspace.createFileSystemWatcher(pattern));

		// When a file changes on disk (e.g., from git checkout), request fresh diagnostics
		this._register(watcher.onDidChange(uri => {
			this.onFileSystemChange(uri);
		}));

		// When a file is deleted on disk, clear its diagnostics
		this._register(watcher.onDidDelete(uri => {
			this.onFileSystemDelete(uri);
		}));

		// When a file is created on disk, request diagnostics for it
		this._register(watcher.onDidCreate(uri => {
			this.onFileSystemCreate(uri);
		}));

		return watcher;
	};

	// Set up watchers for existing workspace folders
	if (vscode.workspace.workspaceFolders) {
		for (const folder of vscode.workspace.workspaceFolders) {
			createWatcher(folder);
		}
	}

	// Listen for workspace folder changes and set up/tear down watchers accordingly
	this._register(vscode.workspace.onDidChangeWorkspaceFolders(e => {
		for (const added of e.added) {
			createWatcher(added);
		}
	}));
}

